const phoneWidth = 75
const angle = 70
const thickness = 3

function main() {
  const base = roundedCuboid({ size: [95, 68, thickness], roundRadius: 5, segments: 20 })
  const support = translate([0, -18, 27], cuboid({ size: [phoneWidth + 6, thickness, 54] }))
  const slot = translate([0, 20, thickness + 3], cuboid({ size: [phoneWidth + 4, thickness + 1, 6] }))
  const guideL = translate([-phoneWidth / 2 - 2, 20, thickness + 5], cuboid({ size: [3, thickness, 8] }))
