const boxHeight = 40
const wallThickness = 2

function main() {
  const outer = roundedCuboid({ size: [boxWidth, boxDepth, boxHeight], roundRadius: 4, segments: 16 })
  const inner = translate([0, 0, wallThickness], roundedCuboid({ size: [boxWidth - wallThickness * 2, boxDepth - wallThickness * 2, boxHeight], roundRadius: 2, segments: 16 }))
