// @material: metal
const bracketWidth = 40
const bracketHeight = 30
const holeCount = 2
const thickness = 4

function main() {
  const base = roundedCuboid({ size: [bracketWidth, bracketHeight, thickness], roundRadius: 3, segments: 16 })
  const spacing = bracketWidth / (holeCount + 1)
  const holes = []
  for (let i = 0; i < holeCount; i++) {
    const x = spacing * (i + 1) - bracketWidth / 2
    holes.push(translate([x, 0, 0], cylinder({ radius: 1.65, height: thickness + 1, segments: 20 })))
    holes.push(translate([x, 0, thickness * 0.3], cylinder({ radiusBottom: 1.65, radiusTop: 3.2, height: thickness * 0.7, segments: 20 })))
  }
  const slotL = translate([-bracketWidth / 2 + 5, 0, 0], cylinder({ radius: 2.2, height: thickness + 1, segments: 16 }))
  const slotR = translate([bracketWidth / 2 - 5, 0, 0], cylinder({ radius: 2.2, height: thickness + 1, segments: 16 }))
  const body = subtract(base, ...holes, slotL, slotR)
  return colorize([0.48, 0.48, 0.54], body)
}
module.exports = { main }

// @material: plastic
const cableCount = 3
const cableDiameter = 4
const wallT = 1.5
const slotR = cableDiameter / 2 + 0.2

function main() {
  const totalWidth = cableCount * (cableDiameter + wallT * 2) + wallT
  const base = cuboid({ size: [totalWidth, 15, 8] })
  let slots = []
  for (let i = 0; i < cableCount; i++) {
    const x = -totalWidth / 2 + wallT + slotR + i * (slotR * 2 + wallT)
    slots.push(translate([x, 0, 2], cylinder({ radius: slotR, height: 10 })))
  }
  return colorize([0.18, 0.52, 0.92], subtract(base, ...slots))
}

module.exports = { main }

// @material: silver
const toothCount = 20  // 齿数 min:8 max:60
const outerR = 28      // 齿顶圆半径 unit:mm min:12 max:80
const gearHeight = 8   // 齿轮厚度 unit:mm min:3 max:20

function main() {
  const rootR  = outerR * 0.78   // 齿根圆半径
  const hubR   = outerR * 0.22   // 中心轮毂半径
  const boreR  = outerR * 0.12   // 安装孔半径

  // ── XZ 平面齿形轮廓（真实锯齿，4点/齿）──
  const pts = []
  const toothHalf = (Math.PI / toothCount) * 0.45
  for (let i = 0; i < toothCount; i++) {
    const a = (i / toothCount) * 2 * Math.PI
    pts.push([rootR  * Math.cos(a - toothHalf),        rootR  * Math.sin(a - toothHalf)])
    pts.push([outerR * Math.cos(a - toothHalf * 0.45), outerR * Math.sin(a - toothHalf * 0.45)])
    pts.push([outerR * Math.cos(a + toothHalf * 0.45), outerR * Math.sin(a + toothHalf * 0.45)])
    pts.push([rootR  * Math.cos(a + toothHalf),        rootR  * Math.sin(a + toothHalf)])
  }
  const gearBody = colorize([0.52, 0.56, 0.62],
    extrudeLinear({ height: gearHeight }, polygon({ points: pts }))
  )

  // ── 辐条（十字型加轻记号）──
  const spokeLen = rootR - hubR - 3
  const spokes = []
  for (let i = 0; i < 4; i++) {
    const a = (i / 4) * Math.PI * 2
    const sa = Math.sin(a), ca = Math.cos(a)
    const mx = ca * (hubR + spokeLen / 2)
    const mz = sa * (hubR + spokeLen / 2)
    spokes.push(colorize([0.42, 0.46, 0.52],
      translate([mx, 1, mz],
        rotate([0, a, 0], cuboid({ size: [spokeLen, gearHeight - 2, outerR * 0.08 + 1] }))
      )
    ))
  }

  // ── 中心轮毂 + 安装孔（视觉标识）──
  const hub = colorize([0.38, 0.40, 0.46],
    translate([0, -1, 0], cylinder({ radius: hubR, height: gearHeight + 2, segments: 24 }))
  )
  const bore = colorize([0.22, 0.22, 0.25],
    translate([0, -2, 0], cylinder({ radius: boreR, height: gearHeight + 4, segments: 16 }))
  )

  return union(gearBody, ...spokes, hub, bore)
}
module.exports = { main }

